# Module defining shape types, interfaces, and base classes

enum ShapeType:
    CIRCLE = 0
    RECTANGLE = 1
    TRIANGLE = 2

enum Color:
    RED = 0xFF0000
    GREEN = 0x00FF00
    BLUE = 0x0000FF

interface IDrawable:
    @virtual
    def draw(self) -> str: ...

    @virtual
    def get_area(self) -> float: ...

interface ITransformable:
    @virtual
    def scale(self, factor: float) -> None: ...

@abstract
class Shape:
    shape_type: ShapeType
    color: Color

    def __init__(self, shape_type: ShapeType, color: Color):
        self.shape_type = shape_type
        self.color = color

    @abstract
    def get_area(self) -> float: ...

    @abstract
    def describe(self) -> str: ...

    def get_color_name(self) -> str:
        if self.color == Color.RED:
            return "Red"
        elif self.color == Color.GREEN:
            return "Green"
        elif self.color == Color.BLUE:
            return "Blue"
        return "Unknown"

class Circle(Shape, IDrawable):
    radius: float

    def __init__(self, radius: float, color: Color):
        super().__init__(ShapeType.CIRCLE, color)
        self.radius = radius

    @override
    def get_area(self) -> float:
        pi: float = 3.14159
        return pi * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(radius={{self.radius:.2f}})"

    @override
    def draw(self) -> str:
        return f"Drawing {{self.get_color_name()}} circle with radius {{self.radius:.1f}}"

class Rectangle(Shape, IDrawable, ITransformable):
    width: float
    height: float

    def __init__(self, width: float, height: float, color: Color):
        super().__init__(ShapeType.RECTANGLE, color)
        self.width = width
        self.height = height

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle({{self.width:.1f}}x{{self.height:.1f}})"

    @override
    def draw(self) -> str:
        return f"Drawing {{self.get_color_name()}} rectangle {{self.width:.1f}}x{{self.height:.1f}}"

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to_origin(self) -> float:
        return pow(self.x * self.x + self.y * self.y, 0.5)

