# Module providing rendering capabilities for shapes
# Demonstrates using types from shapes module

from shapes import IDrawable, ITransformable, Point2D

interface IRenderer:
    @virtual
    def render(self, item: IDrawable) -> str: ...

    @virtual
    def get_name(self) -> str: ...

class ConsoleRenderer(IRenderer):
    render_count: int

    def __init__(self):
        self.render_count = 0

    @override
    def render(self, item: IDrawable) -> str:
        self.render_count = self.render_count + 1
        result: str = item.draw()
        return f"[Console] {{result}}"

    @override
    def get_name(self) -> str:
        return "ConsoleRenderer"

    def get_render_count(self) -> int:
        return self.render_count

class SvgRenderer(IRenderer):
    scale_factor: float

    def __init__(self, scale: float):
        self.scale_factor = scale

    @override
    def render(self, item: IDrawable) -> str:
        if isinstance(item, ITransformable):
            # Apply scale transformation before rendering
            item.scale(self.scale_factor)
        return f"[SVG scale={{self.scale_factor}}] {{item.draw()}}"

    @override
    def get_name(self) -> str:
        return "SvgRenderer"

