# Utility module with helper functions and transformations

from shapes import Shape, Circle, Rectangle, Color, Point2D
from renderers import ConsoleRenderer

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total = total + shape.get_area()
    return total

def create_colorful_circle(radius: float, color_index: int) -> Circle:
    color: Color = Color.RED
    if color_index == 1:
        color = Color.GREEN
    elif color_index == 2:
        color = Color.BLUE
    return Circle(radius, color)

def is_point_in_unit_circle(point: Point2D) -> bool:
    distance: float = point.distance_to_origin()
    return distance <= 1.0

def create_default_renderer() -> ConsoleRenderer:
    return ConsoleRenderer()
